import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Turing Post — 2026-04-07","description":"","frontmatter":{"title":"Turing Post — 2026-04-07","date":"2026-04-07T00:00:00.000Z","source":"Turing Post","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-07-turing-post.md","filePath":"research/ai-news/2026-04/2026-04-07-turing-post.md","lastUpdated":1779894392000}'),o={name:"research/ai-news/2026-04/2026-04-07-turing-post.md"};function i(s,e,l,p,h,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🏛️-turing-post-—-2026-04-07" tabindex="-1">🏛️ Turing Post — 2026-04-07 <a class="header-anchor" href="#🏛️-turing-post-—-2026-04-07" aria-label="Permalink to &quot;🏛️ Turing Post — 2026-04-07&quot;">​</a></h1><blockquote><p>Ksenia Se 主持，95k+ 訂閱；AI/ML 政策、地緣政治與深度洞察 來源：<a href="https://turingpost.substack.com/feed" target="_blank" rel="noreferrer">Turing Post</a></p></blockquote><hr><h2 id="fod-147-can-your-openclaw-dream" tabindex="-1"><a href="https://turingpost.substack.com/p/fod147-can-your-openclaw-dream" target="_blank" rel="noreferrer">FOD#147: Can your OpenClaw dream?</a> <a class="header-anchor" href="#fod-147-can-your-openclaw-dream" aria-label="Permalink to &quot;[FOD#147: Can your OpenClaw dream?](https://turingpost.substack.com/p/fod147-can-your-openclaw-dream)&quot;">​</a></h2><p><em>🏛️ Turing Post | 2026-04-07</em></p><p>This Week in Turing Post:</p><p>Monday-Thursday – ☕️ I’m in an Francisco, attending and moderating two sessions at HumanX – come say hi if you are there. ☕️</p><p>Wednesday / AI 101 series: Gemma 4 and why many OpenClaw users are now switching to it (basically, an Ode to Open Source!)</p><p>Friday / Our new series, <a href="https://www.turingpost.com/t/the-org-age-of-ai" target="_blank" rel="noreferrer">The Org Age of AI,</a> is getting a lot of traction. This time, we’ll discuss how small teams (1–10 people) should think about organizational questions.</p><p>To the main topic →</p><p>/dreaming status</p><p>/dreaming on</p><p>/dreaming off</p><p>/dreaming help</p><p>Dave Morin, OpenClaw Foundation</p><p>Three people you absolutely have to follow if you’re curious about OpenClaw: <a href="https://x.com/steipete" target="_blank" rel="noreferrer">Peter Steinberger</a> (of course), plus two others who consistently share valuable insights – legendary <a href="https://x.com/davemorin" target="_blank" rel="noreferrer">Dave Morin</a> and the always fun (and helpful!) <a href="https://x.com/vincent_koc" target="_blank" rel="noreferrer">Vincent Koc</a>.</p><p>Them and a huge team of maintainers leads OpenClaw as a movement. Last week they introduced a whole list of incredible updates to the lobster (you’ll find them in the news section) but there is other thing that caught my attention.</p><p>Two stories about the inner life of AI that deserve to be read together</p><p>Yesterday, Dave published an article, “<a href="https://x.com/davemorin/status/2040999146694553761" target="_blank" rel="noreferrer">A Theory of Mind in Three Files</a>,” and what he describes there is striking because it reaches for an old vocabulary to explain a very new kind of system: SOUL.md for identity, MEMORY.md for experience, DREAMS.md for integration.</p><p>I think that is exactly what makes OpenClaw so popular – this language, this softness, in a way. I call it kindness. Soul? Dream? We know exactly that in no way do they mean sentience, and that is what makes the language around OpenClaw so unpretentious and real. I am dedicating a whole editorial to that because I think kindness and soul are important for us, humans, if we want to stay human.</p><p>Just to prove that there is no BS about sentience, you only need to look at the lobster <a href="https://docs.openclaw.ai/concepts/dreaming" target="_blank" rel="noreferrer">documentation</a>. It is much more concrete and much less poetic: dreaming is an opt-in background memory consolidation system that sorts recent signals, promotes durable ones into long-term memory, and can write a human-readable dream diary. In other words, the metaphor is doing real interface work. It is translating machine maintenance into a language humans can immediately grasp. And be happy with it.</p><p>Somehow it makes it very clear: OpenClaw serves people because it’s a clever system organized by humans. There is no Terminator script behind it. It feels nice.</p><p>What I found especially interesting was the coincidence that the same company famous for publishing work that often nudges the sentience conversation forward (a view I do not support) published in the same week a very grounded paper <a href="https://transformer-circuits.pub/2026/emotions/index.html" target="_blank" rel="noreferrer">Emotion Concepts and their Function in a Large Language Model.</a> Anthropic’s argument in this work is actually quite careful: they are not claiming that Claude feels emotions or has subjective experience. They are claiming something both narrower and, in practical terms, more useful. They found internal representations of emotion concepts in Claude Sonnet 4.5 and showed that these patterns can causally influence the model’s behavior. Anthropic explicitly says that this does not imply subjective experience, but that reasoning about those representations with the vocabulary of human psychology can still be informative.</p><p>And this is where it becomes interesting in a different way.</p><p>OpenClaw is not just choosing nicer words. It is setting a tone. It uses human language, but in a way that removes the temptation to overinterpret. It gives you “soul” and “dream,” but immediately anchors them in something you can inspect, edit, and understand. You are not asked to believe in anything mysterious. You are invited to look at files.</p><p>That significantly influences the discourse.</p><p>By being gentle and human in how it presents these ideas, OpenClaw actually pushes the conversation in a more technical direction. It lowers the temperature. It replaces speculation with inspectability. It shows that you can talk about identity, memory, even something like “dreaming,” without drifting into mythology.</p><p>I appreciate it. I think we still don’t fully know how to talk about, or even think about, models and agents and their increasing presence in our lives.</p><p>We are going to spend more and more time with systems that stay with us, adapt to us, and become part of everyday life. So it is important to learn how to relate to them without falling into doom scenarios.</p><p>OpenClaw shows that this is possible. And in doing so, it may be pushing the rest of the field in a more grounded direction.</p><p>Topic 2: In this Attention Span I’m talking about the model that surprised me recently (and you might not have heard about it!) (based on the “<a href="https://thefocus.ai/posts/mcp-tool-eval-mercury-umwelten/" target="_blank" rel="noreferrer">Can LLMs Use Real-World Tools</a>?” report by TheFocus.AI). <a href="https://youtu.be/Dpsv-1CXotA" target="_blank" rel="noreferrer">Watch the episode!</a></p><p>Follow us on 🎥<a href="https://www.youtube.com/@RealTuringPost" target="_blank" rel="noreferrer"> YouTube</a> <a href="https://x.com/TheTuringPost" target="_blank" rel="noreferrer">Twitter</a> <a href="https://huggingface.co/Kseniase" target="_blank" rel="noreferrer"> Hugging Face </a>🤗</p><p>Twitter Library</p><p><a href="https://www.turingpost.com/p/agentselfimprovement" target="_blank" rel="noreferrer">9 Open Agents That Improve Themselves</a></p><p>We are reading/watching/learning:</p><p><a href="https://x.com/jack/status/2039003879841362278" target="_blank" rel="noreferrer">From Hierarchy to Intelligence</a> by Jack Dorsey. It’s a good reading along <a href="https://www.turingpost.com/t/the-org-age-of-ai" target="_blank" rel="noreferrer">The Org Age of AI</a>, we will be discussing this article in more detail in the future episodes.</p><p>Andrej Karpathy’s tweet “LLM Knowledge Bases“ has 16 million views. And for a reason. <a href="https://x.com/karpathy/status/2040470801506541998" target="_blank" rel="noreferrer">Here you can find both that post and Andrej’s update</a>. Will be covering it in more details as well later.</p><p><a href="https://steve-yegge.medium.com/vibe-maintainer-a2273a841040" target="_blank" rel="noreferrer">Vibe Maintainer</a> by Steve Yagge</p><p>News from the usual suspects ™</p><p>OpenClaw – Now With a Studio Very impressive update: OpenClaw 2026.4.5 <a href="https://x.com/openclaw/status/2040998577372021026" target="_blank" rel="noreferrer">arrives</a> with built-in video and music generation, a real /dreaming feature, structured task progress, better prompt-cache reuse, and support for 12 more languages across its UI and docs. It also expands its model bazaar: image generation via Comfy, fal, Google, MiniMax, and OpenAI; music through Comfy, Google, and MiniMax; video from practically half the industry. A tidy reminder that “bring your own model” can become an empire if left unsupervised.</p><p>Meanwhile, Anthropic</p><p>Declared War on the Harnesses</p><p>Users of third-party agent platforms – including OpenClaw – started receiving emails: subscriptions “weren’t designed for these usage patterns,” and harness usage will be billed separately at undisclosed rates. Boris Cherny confirmed the changes. The timing: OpenAI is actively courting the same developer audience. Anthropic introduced Claude Channels in March as the official integration path. Is this about compute costs or about controlling the agent layer?</p><p>goes big on compute (very big) Fresh off throttling demand, Anthropic is <a href="https://www.anthropic.com/news/google-broadcom-partnership-compute" target="_blank" rel="noreferrer">doubling down on supply</a> – signing a multi-gigawatt TPU deal with Google and Broadcom. With revenue reportedly surging past $30B (annualized) and enterprise adoption accelerating, this is less “capacity planning” and more “industrial-scale ambition.” The message is clear: if AI is the new electricity, Anthropic is buying the power plants early.</p><p>OpenAI</p><p>War Chest, Fully Loaded OpenAI just <a href="https://openai.com/index/accelerating-the-next-phase-ai/" target="_blank" rel="noreferrer">secured</a> a staggering $122B round at an $852B valuation. With $2B in monthly revenue and a fast-closing march toward 1B weekly users, this is less “startup” and more sovereign entity. The strategy: more compute, better models, tighter flywheel – repeat until intelligence becomes a utility.</p><p>Buying the Narrative OpenAI <a href="https://openai.com/index/openai-acquires-tbpn/" target="_blank" rel="noreferrer">acquires</a> TBPN, the fast-rising tech talk show, in a move that blends media, influence, and distribution. Crucially, TBPN keeps editorial independence–credibility intact, megaphone amplified. OpenAI is trying to shape the conversation around them. In this cycle, controlling the story may be nearly as valuable as controlling the stack.</p><p>Hugging Face is filling the gap</p><p>Clem Delangue, HF’s CEO, <a href="https://x.com/ClementDelangue/status/2041189872556269697" target="_blank" rel="noreferrer">started</a> publishing production agent traces this week – real workflow logs from actual agentic tasks. This is the actual chain of reasoning a model uses when it plans, revises, and executes a multi-step task. OpenAI, Anthropic, and Google have been hoarding this data. Open-sourcing it changes the competitive dynamics in ways that won’t show up in benchmarks for a while.</p><p>Perplexity – Taxes, but Make It Autonomous Perplexity <a href="https://www.perplexity.ai/hub/blog/introducing-computer-for-taxes" target="_blank" rel="noreferrer">rolls out </a>“Computer for Taxes,” aiming to tame the annual ritual of confusion and mild despair. With modular, up-to-date tax knowledge, it drafts IRS forms, audits professional returns, and even builds custom tools for complex scenarios. In testing, it caught costly human errors – politely proving accountants aren’t infallible. Filing season is here to prove it.</p><p>X Devs – Turning Twitter into an AI Action Layer That’s a surprising announcements, because for me that was the only use of Grok – to parse X. But let’s see: The repo effectively turns X into something AI agents can use, not just read. Instead of scraping feeds, models can now post, search, DM, and analyze via structured tools. It is trying to make social platforms programmable surfaces for AI workflows <a href="https://github.com/xdevplatform/xmcp" target="_blank" rel="noreferrer">→their GitHub</a></p><p>MemPalace – Milla Jovovich Walks Into AI Yes, that Milla Jovovich. MemPalace, an open-source AI memory system she helped build, is suddenly one of the more unexpected names in the AI conversation. The project promises local-first memory, sharp benchmark results, and zero cloud dependence. In a field crowded with predictable launches from familiar labs, this one arrives like a plot twist—half engineering story, half cultural moment <a href="https://x.com/bensig/status/2041236952998171118" target="_blank" rel="noreferrer">→tweet of her partner</a></p><p>🔦 Models and Agents Highlight</p><p>Open-weight models (control, portability, post-training)</p><p>Trinity-Large-Thinking by Arcee Improves multi-turn reasoning and tool orchestration for long-running agent workflows, with a focus on coherence, instruction fidelity, and stability under real production constraints, while remaining fully open-weight for inspection, distillation, and self-hosting <a href="https://huggingface.co/arcee-ai" target="_blank" rel="noreferrer">→get the model</a></p><p>Gemma 4 by Google Expands the open model stack with multiple sizes and efficient architectures, emphasizing deployability, customization, and lower-cost inference for real-world products rather than centralized API usage <a href="https://deepmind.google/models/gemma/" target="_blank" rel="noreferrer">→ get the model</a></p><p>Qwen3.6-Plus Pushes open models toward near-frontier performance on reasoning and agentic benchmarks, making open-weight systems increasingly viable as primary production backbones <a href="https://qwen.ai/blog?id=qwen3.6" target="_blank" rel="noreferrer">→get the model</a></p><p>Closed models (platform-controlled intelligence layer)</p><p>By Microsoft:</p><p>MAI-Transcribe-1 Turns speech recognition into a native platform capability with production-grade accuracy and latency, positioning transcription as core infrastructure <a href="https://ai.azure.com/catalog/models/MAI-Transcribe-1" target="_blank" rel="noreferrer">→read their blog</a></p><p>MAI-Voice-1 Enables controllable, identity-consistent voice generation, pushing voice toward becoming a primary software interface rather than an output format <a href="https://microsoft.ai/news/two-new-in-house-models/" target="_blank" rel="noreferrer">→read their blog</a></p><p>MAI-Image-2 Advances image generation quality and text rendering, integrating visual creation directly into productivity and enterprise workflows <a href="https://microsoft.ai/news/introducing-mai-image-2/" target="_blank" rel="noreferrer">→read their blog</a></p><p>GLM-5V Turbo by Z.ai Extends multimodal capability into interface-level reasoning, enabling models to operate across screens, files, and visual environments within controlled platform ecosystems <a href="https://docs.z.ai/guides/vlm/glm-5v-turbo" target="_blank" rel="noreferrer">→read their blog</a></p><p>🔦 Open models are closing the capability gap while keeping control, and closed platforms are moving aggressively to own the core modalities that define how software is experienced.</p><p>Research and Survey Highlights</p><p>A Survey of On-Policy Distillation for Large Language Models – Unifies distillation under an on-policy framework where models learn from their own generated trajectories, which connects directly to how agent loops and RL-style reasoning systems are actually trained <a href="https://arxiv.org/abs/2604.00626" target="_blank" rel="noreferrer">→read the paper</a></p><p>The Latent Space: Foundation, Evolution, Mechanism, Ability, and Outlook</p><p>provides a unified and up-to-date landscape of latent space in language-based models <a href="https://arxiv.org/abs/2604.02029" target="_blank" rel="noreferrer">→read the paper</a></p><p>Rest of research from the last week</p><hr>',70)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
